class CheckpointDownloader:
    """Downloads and caches model checkpoints from public repositories."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        logger.info(f"Checkpoint cache directory: {self.cache_dir}")

    def download_checkpoint(
        self, url: str, filename: Optional[str] = None, force: bool = False
    ) -> Path:
        """Download a checkpoint from a URL."""
        if filename is None:
            filename = url.split("/")[-1]

        filepath = self.cache_dir / filename

        if filepath.exists() and not force:
            logger.info(f"Checkpoint already cached: {filepath}")
            return filepath

        logger.info(f"Downloading checkpoint from: {url}")
        state_dict = torch.hub.load_state_dict_from_url(
            url, model_dir=str(self.cache_dir), map_location="cpu", file_name=filename
        )

        # If hub already saved it, great. Otherwise save manually.
        if not filepath.exists():
            torch.save(state_dict, filepath)
            logger.info(f"Saved checkpoint to: {filepath}")

        return filepath

    def load_checkpoint(
        self, path: str, map_location: str = "cpu"
    ) -> Dict[str, Any]:
        """Load a checkpoint using torch.load."""
        logger.info(f"Loading checkpoint from: {path}")
        checkpoint = torch.load(path, map_location=map_location, weights_only=False)
        return checkpoint

    def download_from_registry(
        self, model_name: str, force: bool = False
    ) -> Path:
        """Download a model checkpoint from the registry."""
        if model_name not in MODEL_REGISTRY:
            raise ValueError(
                f"Model '{model_name}' not in registry. "
                f"Available: {list(MODEL_REGISTRY.keys())}"
            )
        info = MODEL_REGISTRY[model_name]
        return self.download_checkpoint(info["url"], force=force)


# ==============================================================================
# Custom Dataset Wrapper
# ==============================================================================

class CustomImageDataset(Dataset):
    """
    Custom dataset that loads images from a directory structure:
        root/class_name/image.jpg
    Falls back to a synthetic dataset for demonstration.
    """

    def __init__(
        self,
        root_dir: Optional[str] = None,
        transform: Optional[transforms.Compose] = None,
        num_classes: int = 10,
        num_samples: int = 1000,
        image_size: int = 224,
    ):
        self.transform = transform
        self.num_classes = num_classes
        self.use_synthetic = root_dir is None or not Path(root_dir).exists()

        if self.use_synthetic:
            logger.info(
                f"Using synthetic dataset: {num_samples} samples, "
                f"{num_classes} classes, {image_size}x{image_size} images"
            )
            self.num_samples = num_samples
            self.image_size = image_size
            self.data = torch.randn(num_samples, 3, image_size, image_size)
            self.targets = torch.randint(0, num_classes, (num_samples,))
        else:
            logger.info(f"Loading dataset from: {root_dir}")
            self.dataset = torchvision.datasets.ImageFolder(
                root_dir, transform=transform
            )
            self.num_classes = len(self.dataset.classes)
            self.num_samples = len(self.dataset)

    def __len__(self) -> int:
        return self.num_samples

    def __getitem__(self, idx: int) -> Tuple[torch.Tensor, int]:
        if self.use_synthetic:
            image = self.data[idx]
            label = self.targets[idx].item()
            if self.transform:
                image = self.transform(image)
            return image, label
        else:
            return self.dataset[idx]


