class ModelBuilder:
    """Builds and adapts pretrained models for transfer learning."""

    def __init__(self, downloader: CheckpointDownloader):
        self.downloader = downloader

    def build_model(
        self,
        model_name: str,
        num_classes: int,
        freeze_backbone: bool = True,
        freeze_until_layer: Optional[str] = None,
        custom_checkpoint_path: Optional[str] = None,
    ) -> nn.Module:
        """
        Build a pretrained model adapted for a custom number of classes.

        Args:
            model_name: Name of the model in the registry
            num_classes: Number of output classes
            freeze_backbone: Whether to freeze backbone parameters
            freeze_until_layer: Freeze all layers until this named layer
            custom_checkpoint_path: Path to a custom checkpoint file
        """
        if model_name not in MODEL_REGISTRY:
            raise ValueError(f"Unknown model: {model_name}")

        info = MODEL_REGISTRY[model_name]

        # Create model architecture (without pretrained weights initially)
        model = info["constructor"](weights=None)

        # Load checkpoint
        if custom_checkpoint_path:
            logger.info(f"Loading custom checkpoint: {custom_checkpoint_path}")
            state_dict = self.downloader.load_checkpoint(custom_checkpoint_path)
        else:
            checkpoint_path = self.downloader.download_from_registry(model_name)
            state_dict = self.downloader.load_checkpoint(str(checkpoint_path))

        # Handle state_dict formats (some checkpoints wrap in 'state_dict' key)
        if isinstance(state_dict, dict) and "state_dict" in state_dict:
            state_dict = state_dict["state_dict"]
        if isinstance(state_dict, dict) and "model_state_dict" in state_dict:
            state_dict = state_dict["model_state_dict"]

        # Load pretrained weights (allow partial loading for classifier mismatch)
        try:
            model.load_state_dict(state_dict, strict=True)
            logger.info("Loaded all pretrained weights successfully")
        except RuntimeError:
            # Partial loading - skip mismatched layers
            model_dict = model.state_dict()
            filtered_dict = {
                k: v
                for k, v in state_dict.items()
                if k in model_dict and v.shape == model_dict[k].shape
            }
            model_dict.update(filtered_dict)
            model.load_state_dict(model_dict)
            logger.info(
                f"Partially loaded pretrained weights: "
                f"{len(filtered_dict)}/{len(model_dict)} layers"
            )

        # Replace classifier head for new number of classes
        model = self._replace_classifier(model, model_name, num_classes, info)

        # Freeze layers
        if freeze_backbone:
            self._freeze_backbone(model, model_name, freeze_until_layer, info)

        # Log model info
        total_params = sum(p.numel() for p in model.parameters())
        trainable_params = sum(
            p.numel() for p in model.parameters() if p.requires_grad
        )
        logger.info(
            f"Model: {model_name} | Total params: {total_params:,} | "
            f"Trainable params: {trainable_params:,} "
            f"({100 * trainable_params / total_params:.1f}%)"
        )

        return model

    def _replace_classifier(
        self,
        model: nn.Module,
        model_name: str,
        num_classes: int,
        info: Dict[str, Any],
    ) -> nn.Module:
        """Replace the classifier head of the model."""
        classifier_attr = info["classifier_attr"]

        if model_name.startswith("resnet"):
            in_features = model.fc.in_features
            model.fc = nn.Sequential(
                nn.Dropout(0.5),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Dropout(0.3),
                nn.Linear(512, num_classes),
            )
            logger.info(
                f"Replaced fc: {in_features} -> 512 -> {num_classes}"
            )

        elif model_name.startswith("vgg"):
            in_features = model.classifier[6].in_features
            model.classifier[6] = nn.Linear(in_features, num_classes)
            logger.info(
                f"Replaced classifier[6]: {in_features} -> {num_classes}"
            )

        elif model_name.startswith("mobilenet"):
            in_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.2),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced classifier: {in_features} -> {num_classes}"
            )

        elif model_name.startswith("efficientnet"):
            in_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.2),
                nn.Linear(in_features, num_classes),
            )
            logger.info(
                f"Replaced classifier: {in_features} -> {num_classes}"
            )

        else:
            logger.warning(
                f"No specific classifier replacement for {model_name}. "
                f"Attempting generic replacement."
            )
            classifier = getattr(model, classifier_attr)
            if isinstance(classifier, nn.Linear):
                in_features = classifier.in_features
                setattr(model, classifier_attr, nn.Linear(in_features, num_classes))

        return model

    def _freeze_backbone(
        self,
        model: nn.Module,
        model_name: str,
        freeze_until_layer: Optional[str],
        info: Dict[str, Any],
    ) -> None:
        """Freeze backbone layers, keeping classifier trainable."""
        classifier_attr = info["classifier_attr"]

        if freeze_until_layer:
            # Freeze all layers until the specified layer
            freeze = True
            for name, param in model.named_parameters():
                if freeze_until_layer in name:
                    freeze = False
                param.requires_grad = not freeze
            logger.info(f"Frozen all layers until: {freeze_until_layer}")
        else:
            # Freeze everything except the classifier
            for name, param in model.named_parameters():
                if classifier_attr not in name:
                    param.requires_grad = False
            logger.info(
                f"Frozen all layers except '{classifier_attr}'"
            )


